concept.syntax:
// Standard if/else
if score >= 60 {
    println!("Pass");
} else {
    println!("Fail");
}

// if as expression
let label = if score >= 60 { "Pass" } else { "Fail" };

// match
match grade {
    'A' => println!("Excellent"),
    'B' | 'C' => println!("Good"),
    _ => println!("Keep going"),
}

demo.code:
fn main() {
    let score = 75;
    let grade = if score >= 90 { "A" }
                else if score >= 70 { "B" }
                else { "C" };
    println!("Grade: {}", grade);
    match grade {
        "A" => println!("Excellent!"),
        "B" => println!("Good."),
        _   => println!("Keep going."),
    }
}

